    {
      "title": "The First Language Model: Markov Chains and N-Grams",
      "scope": "Moving from the abstract goal of generation to the first mathematical implementation in 1913. We explore how Andrey Markov used probability to predict the next letter in a sequence based only on its immediate history, forming the bedrock of sequential text generation.",
      "concepts": [
        "Markov Chains and n-gram models"
      ]
    },
    {
      "title": "Quantifying Surprise: Information Theory and Shannon Entropy",
      "scope": "Building on the sequential predictions of Markov chains, we introduce Claude Shannon's 1948 framework for measuring unpredictability in communication. This provides the mathematical intuition for evaluating how well a model compresses and understands language.",
      "concepts": [
        "Information Theory and Shannon Entropy"
      ]
    },
    {
      "title": "Language as a Decoding Problem: The Noisy Channel Model",
      "scope": "Connects Shannon's information theory to the real-world problem of translation. We explore the brilliant intuition of treating a foreign language as an encrypted or 'noisy' version of our own, using probability theory to reconstruct the original message.",
      "concepts": [
        "The 'Noisy Channel' model of translation"
      ]
    },
    {
      "title": "Training by Counting: Maximum Likelihood Estimation (MLE)",
      "scope": "Explains the exact statistical mechanism used to 'teach' these early n-gram and noisy channel models. We look intuitively at how MLE relies on counting historical text occurrences to calculate the most probable next word, without getting bogged down in derivations.",
      "concepts": [
        "Maximum Likelihood Estimation (MLE) in NLP"
      ]
    },
    {
      "title": "The Wall: The Curse of Dimensionality",
      "scope": "Reveals the fatal engineering bottleneck of counting-based probabilistic models. We explore why trying to remember longer historical contexts causes the required vocabulary combinations to explode exponentially, forcing the eventual shift to neural architectures.",
      "concepts": [
        "The Curse of Dimensionality in vocabulary space"
      ]
    }
  ]
}

